class Solution {
public:
  bool solve(vector<int>& nums) {
    int n = nums.size();
    for (int i = 1; i < n; i++) {
      for (int j = 0; j < i; j++) {
        if (nums[j] > nums[i])
          std::swap(nums[j], nums[i]);
      }
    }
    return true;
  }
};

